FormulaFieldDefinitions.FormulaFieldDefinition:
WhilePrintingRecords;
StringVar ConcatenatedNOTES;
If Not InRepeatedGroupHeader Then
    ConcatenatedNOTES := "";

WhilePrintingRecords;
if {LOAD_PLAN.NOTES} like ''
    then StringVar ConcatenatedNOTES := ConcatenatedNOTES
else StringVar ConcatenatedNOTES := ConcatenatedNOTES + ' ' + {LOAD_PLAN.NOTES};

TextObject.Text:
Load Number: {LOAD_PLAN.LOAD_NO}
Order Qty: {@OrderQtyTotal}
Staged Qty: {@StagingQtyTotal}
